const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 86400000);
return [{ json: { from_iso: weekAgo.toISOString(), to_iso: now.toISOString() } }];

const profiles = items[0].json || [];
const sales = $('Fetch Sales Week').first().json || [];
const results = [];
for (const profile of profiles) {
  if (!profile.email) continue;
  const userSales = sales.filter(s => s.user_id === profile.id);
  const totalCA = userSales.reduce((sum, s) => sum + (Number(s.price) || 0), 0);
  const totalCommission = userSales.reduce((sum, s) => sum + (Number(s.commission_amount) || 0), 0);
  const totalUrssaf = userSales.reduce((sum, s) => sum + (Number(s.urssaf_amount) || 0), 0);
  const totalNet = userSales.reduce((sum, s) => sum + (Number(s.net_profit) || 0), 0);
  results.push({
    json: {
      user_id: profile.id,
      email: profile.email,
      full_name: profile.full_name || 'Alison',
      business_name: profile.business_name || 'Visit & Smile',
      nb_ventes: userSales.length,
      total_ca: totalCA.toFixed(2),
      total_commission: totalCommission.toFixed(2),
      total_urssaf: totalUrssaf.toFixed(2),
      total_net: totalNet.toFixed(2),
      ventes_detail: userSales.map(s => `${s.property_address || s.title || 'Bien'} - ${Number(s.price).toLocaleString('fr-FR')} EUR`).join('<br>') || 'Aucune vente cette semaine'
    }
  });
}
return results;

